const CHAR_TOM="data:image/png;base64,";
const CHAR_AMARA="data:image/png;base64,";
const CHAR_KENJI="data:image/png;base64,";
const CHAR_MARCUS="data:image/png;base64,";


const AGENTS = [
  {name:"Amara",img:CHAR_AMARA,personality:"Friendly, chatty, happy",gender:"Female",voice:"British"},
  {name:"Grace",img:CHAR_GRACE,personality:"Warm professional",gender:"Female",voice:"British"},
  {name:"Kenji",img:CHAR_KENJI,personality:"Confident friendly",gender:"Male",voice:"British"},
  {name:"Marcus",img:CHAR_MARCUS,personality:"Direct warm professional",gender:"Male",voice:"British (Scottish)"},
  {name:"Priya",img:CHAR_PRIYA,personality:"Formal corporate",gender:"Female",voice:"British (Scottish)"},
  {name:"Ruby",img:CHAR_RUBY,personality:"Warm casual",gender:"Female",voice:"British"},
  {name:"Tom",img:CHAR_TOM,personality:"Formal corporate",gender:"Male",voice:"British"},
];

const lbl = { display:"block", fontSize:13, fontWeight:600, color:T.lightSlate, marginBottom:6, letterSpacing:"0.02em" };

function Logo({size=28,showText=false}) {
  return <div style={{display:"flex",alignItems:"center",gap:8}}>
    <img src={LOGO_SM} alt="Vazzlo" style={{height:size*3,width:"auto"}}/>
    {showText&&<span style={{fontSize:size*0.57,fontWeight:700,color:T.white,letterSpacing:"-0.02em"}}>Vazzlo</span>}
  </div>;
}

function LogoLarge() {
  return <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:8}}>
    <img src={LOGO_MD} alt="Vazzlo" style={{height:140,width:"auto"}}/>
  </div>;
}

const navBtn = {
  padding:"10px 20px", borderRadius:8, border:`1.5px solid ${T.cyan}`,
  background:"transparent", color:T.white, fontSize:13, fontWeight:600,
  fontFamily:font, cursor:"pointer", transition:"all 0.2s",
};

function Nav({onNavigate,current}) {
  const isDash = current==="affDash"||current==="custDash";
  const [hov,setHov]=useState(null);
  const hoverStyle = {background:`rgba(0,169,206,0.2)`};
  const nb = (label, target, idx) => (
    <button style={{...navBtn, ...(hov===idx?hoverStyle:{})}} onMouseEnter={()=>setHov(idx)} onMouseLeave={()=>setHov(null)} onClick={()=>onNavigate(target)}>{label}</button>
  );

  let buttons = null;
  if (isDash) {
    buttons = nb("Log out","home",0);
  } else if (current==="home"||current==="signup") {
    buttons = <>{nb("Affiliate Homepage","affiliate",0)}{nb("Login","login",1)}</>;
  } else if (current==="affiliate"||current==="affSignup") {
    buttons = <>{nb("Customer Homepage","home",0)}{nb("Login","login",1)}</>;
  } else if (current==="login") {
    buttons = <>{nb("Customer Homepage","home",0)}{nb("Affiliate Homepage","affiliate",1)}</>;
  }

  return <nav style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"16px 32px",borderBottom:`1px solid ${T.border}`,background:"rgba(10,22,40,0.9)",backdropFilter:"blur(12px)",position:"sticky",top:0,zIndex:100}}>
    <div style={{cursor:"pointer"}} onClick={()=>onNavigate("home")}><Logo/></div>
    <div style={{display:"flex",gap:8,alignItems:"center"}}>{buttons}</div>
  </nav>;
}

