// UNIFIED LOGIN
// ════════════════════════════════════════════════════
function LoginPage({onNavigate}) {
  return <div style={{maxWidth:400,margin:"60px auto",padding:"0 24px",textAlign:"center"}}>
    <h2 style={{fontSize:24,fontWeight:700,color:T.white,margin:"40px 0 8px"}}>Login</h2>
    <p style={{color:T.slate,marginBottom:24,fontSize:14}}>Access your dashboard, messages, and settings.</p>
    <button style={{width:"100%",padding:"12px",borderRadius:8,border:`1px solid ${T.border}`,background:"rgba(255,255,255,0.04)",color:T.white,fontSize:14,fontFamily:font,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:10,marginBottom:16}} onClick={()=>onNavigate("custDash")}>
      <svg width="18" height="18" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
      Sign in with Google
    </button>
    <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16}}>
      <div style={{flex:1,height:1,background:T.border}}/>
      <span style={{fontSize:12,color:T.slate}}>or use email</span>
      <div style={{flex:1,height:1,background:T.border}}/>
    </div>
    <div style={{marginBottom:16,textAlign:"left"}}><label style={lbl}>Email</label><input style={inp} type="email" placeholder="you@yourbusiness.co.uk"/></div>
    <div style={{marginBottom:20,textAlign:"left"}}><label style={lbl}>Password</label><input style={inp} type="password" placeholder="••••••••"/></div>
    <button style={{...btn(true),width:"100%",marginBottom:12}} onClick={()=>onNavigate("custDash")}>Log in</button>
    <p style={{fontSize:13,color:T.cyan,cursor:"pointer"}}>Forgot password?</p>
    <p style={{fontSize:13,color:T.slate,marginTop:16}}>Don't have an account? Sign up as a <span style={{color:T.cyan,cursor:"pointer"}} onClick={()=>onNavigate("signup")}>Customer</span> or <span style={{color:T.cyan,cursor:"pointer"}} onClick={()=>onNavigate("affiliate")}>Affiliate</span></p>

    {/* Test buttons for development */}
    <div style={{marginTop:32,padding:20,borderRadius:12,border:`1px dashed ${T.border}`,background:"rgba(255,255,255,0.02)"}}>
      <div style={{fontSize:12,fontWeight:600,color:T.lightSlate,marginBottom:12,textTransform:"uppercase",letterSpacing:"0.08em"}}>Development Test Logins</div>
      <div style={{display:"flex",gap:8}}>
        <button style={{flex:1,padding:"10px",borderRadius:8,border:`1px solid ${T.teal}`,background:"rgba(100,204,201,0.08)",color:T.teal,fontSize:13,fontFamily:font,cursor:"pointer",fontWeight:600}} onClick={()=>onNavigate("custDash")}>Login as Test Customer</button>
        <button style={{flex:1,padding:"10px",borderRadius:8,border:`1px solid ${T.purple}`,background:"rgba(168,85,247,0.08)",color:T.purple,fontSize:13,fontFamily:font,cursor:"pointer",fontWeight:600}} onClick={()=>onNavigate("affDash")}>Login as Test Affiliate</button>
      </div>
    </div>
  </div>;
}

// ════════════════════════════════════════════════════
// APP ROUTER
// ════════════════════════════════════════════════════
export default function App() {
  const [page,setPage]=useState("home");
  return <div style={{minHeight:"100vh",background:T.dark,color:T.white,fontFamily:font,WebkitFontSmoothing:"antialiased"}}>
    <style>{`select option{background:#0F2341;color:#ffffff}select option:checked{background:#00A9CE;color:#ffffff}`}</style>
    <Nav onNavigate={setPage} current={page}/>
    {page==="home"&&<HomePage onNavigate={setPage}/>}
    {page==="signup"&&<SignupFlow onNavigate={setPage}/>}
    {page==="affiliate"&&<AffiliateFlow onNavigate={setPage} startStep={0}/>}
    {page==="affSignup"&&<AffiliateFlow onNavigate={setPage} startStep={1}/>}
    {page==="affDash"&&<AffiliateDashboard onNavigate={setPage}/>}
    {page==="login"&&<LoginPage onNavigate={setPage}/>}
    {page==="affLogin"&&<LoginPage onNavigate={setPage}/>}
    {page==="custLogin"&&<LoginPage onNavigate={setPage}/>}
    {page==="custDash"&&<CustomerDashboard onNavigate={setPage}/>}
  </div>;
}
